  const label = `${completed}/${total}`;
  return (
    <span className="checklist-pill" title={`Checklist progress: ${label}`} aria-label={`Checklist progress: ${label}`}>
      <Check size={12} aria-hidden="true" />
      <span>{label}</span>
    </span>
  );
};

const extractExcerpt = (markdown: string): string => {
  const text = markdown
    .replace(/^# .+$/m, "")
    .replace(/^## .+$/gm, "")
    .replace(/[-*]\s+/g, "")
    .replace(/\s+/g, " ")
    .trim();
  return text.length > 160 ? `${text.slice(0, 157)}...` : text;
};

const authoringStateFromLegacyRunStatus = (frontMatter: TicketFrontMatter): TicketFrontMatter["authoringState"] => {
  if (frontMatter.authoringState && frontMatter.authoringState !== "rough") return frontMatter.authoringState;
  switch (frontMatter.runStatus) {
    case "drafting":
      return "drafting";
    case "draft_complete":
    case "completed":
      return "reviewing";
    case "blocked":
      return "needs_input";
    case "queued":
    case "running":
      return "ready";
    default:
      return frontMatter.authoringState ?? "rough";
  }
};

