        {tickets.map((ticket) => (
          <DraggableCard key={ticket.id} ticket={ticket} onOpen={onOpen} />
        ))}
        {tickets.length === 0 && <div className="empty-column">No tickets</div>}
      </div>
    </section>
  );
}

